import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";import{n as o,t as s}from"./chunks/gradle-prompt.DgUqZl-T.js";const c=JSON.parse(`{"title":"Создание проекта","description":"Пошаговое руководство по созданию нового проекта мода с использованием генератора шаблонов Fabric.","frontmatter":{"title":"Создание проекта","description":"Пошаговое руководство по созданию нового проекта мода с использованием генератора шаблонов Fabric.","authors":["IMB11","Cactooz"],"files":[]},"headers":[],"relativePath":"ru_ru/1.21.4/develop/getting-started/creating-a-project.md","filePath":"versions/1.21.4/translated/ru_ru/develop/getting-started/creating-a-project.md","lastUpdated":1760721669000}`);var l={name:`ru_ru/1.21.4/develop/getting-started/creating-a-project.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Создание проекта <a class="header-anchor" href="#h1" aria-label="Permalink to “Создание проекта”">​</a></h1><p>Fabric предоставляет лёгкий путь создания новых проектов мода используя генератор шаблонов модов Fabric, если вы хотите, вы можете создать новый проект используя репозиторий примерного мода, вам следует перейти на <a href="#manual-project-creation">Создание проекта вручную</a>.</p><h2 id="generating-a-project" tabindex="-1">Генерирование проекта <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “Генерирование проекта”">​</a></h2><p>Вы можете использовать <a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Генератор модов Fabric Template</a> для создания нового проекта для вашего мода. Вам следует заполнить обязательные поля, такие как имя мода, имя пакета и версию Minecraft, для которой вы хотите разрабатывать.</p><p>Имя пакета должно быть написано строчными буквами, разделено точками и быть уникальным, чтобы избежать конфликтов с пакетами других программистов. Обычно он форматируется как обратный интернет-домен, например com.example.mod-id.</p><p><img src="/assets/develop/getting-started/template-generator.png" alt="Предварительный просмотр генератора" loading="lazy"></p><p>Если вы хотите использовать Kotlin, использовать официальные сопоставления Mojang вместо сопоставлений Yarn или хотите добавить генераторы данных, вы можете выбрать соответствующие параметры в разделе «Дополнительные параметры».</p><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="Секция расширенных настроек" loading="lazy"></p><p>После того как вы заполнили обязательные поля, нажмите на кнопку <code>Generate</code>, и генератор для вас создадит новый проект в форме zip-файла.</p><p>Вам следует извлечь этот zip-файл в выбранное вами место, а затем открыть извлечённую папку в IntelliJ IDEA:</p><p><img src="/assets/develop/getting-started/open-project.png" alt="Открытый интерпретатор проекта" loading="lazy"></p><h2 id="importing-the-project" tabindex="-1">Импортирование проекта <a class="header-anchor" href="#importing-the-project" aria-label="Permalink to “Импортирование проекта”">​</a></h2><p>После того как вы открыли проект в IntelliJ IDEA, IDE должен автоматически загрузить конфигурацию Gradle проекта и выполнит необходимые задачи по настройке.</p><p>Если вы получите уведомление, говорящее о скрипте сборки Gradle, вам следует нажать кнопку <code>Import Gradle Project</code>:</p><p><img src="/assets/develop/getting-started/gradle-prompt.png" alt="Интерпретатор Gradle" loading="lazy"></p><p>После того как ваш проект был импортирован, вы должны увидеть файлы проекта в проводнике проекта, и сможете начать разработку вашего мода.</p><h2 id="manual-project-creation" tabindex="-1">Создание проекта вручную <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “Создание проекта вручную”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Для клонирования репозитория примера мода вам потребуется установленный <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a>.</p></div><p>Если вы не можете использовать Fabric Template Mod Generator, вы можете создать новый проект вручную, следуя этим шагам.</p><p>Первое, клонируйте репозиторий примера мода используя Git:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">клон</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-mod-project</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Это клонирует репозиторий в новую папку под названием <code>my-mod-project</code>.</p><p>Затем, вы должны удалить папку <code>.git</code> из клонированного репозитория, и затем открыть проект в IntelliJ IDEA. Если папка <code>.git</code> не отображается, вам следует включить отображение скрытых элементов в вашем файловом менеджере.</p><p>После того как вы открыли проект в IntelliJ IDEA, оно должно автоматически загрузить конфигурацию Gradle проекта и должно выполнить необходимые задачи по настройке.</p><p>Опять же, как описывалось выше, если вы получите уведомление, говорящее о скрипте сборки Gradle, вам следует нажать кнопку <code>Import Gradle Project</code>.</p><h3 id="modifying-the-template" tabindex="-1">Изменение Шаблона <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “Изменение Шаблона”">​</a></h3><p>После импорта проекта вам следует изменить детали проекта, чтобы они соответствовали деталям вашего мода:</p><ul><li>Измените файл <code>gradle.properties</code> в вашем проекте, чтобы изменить свойства <code>maven_group</code> и <code>archive_base_name</code> чтобы соответствовать деталям вашего мода.</li><li>Измените файл <code>fabric.mod.json</code>, чтобы изменить свойства <code>id</code>, <code>name</code>, и <code>description</code>, чтобы соответствовать деталям вашего мода.</li><li>Убедитесь, что вы обновили версии Minecraft, маппингов, Loader и Loom — все из которых можно запросить через <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a> — чтобы они соответствовали версиям, которые вы хотите поддерживать.</li></ul><p>Вы конечно же можете изменить имя пакета и основной класс мода, чтобы соответствовать деталям вашего мода.</p>`,29)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};